import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm, Controller } from 'react-hook-form';
import type { SubmitHandler } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation } from '@tanstack/react-query';
import { z } from 'zod';
import { Mail, Lock, Loader2, Clock } from 'lucide-react';

import { authService as accountService } from '@/api/auth/authService';
import { getApiErrorMessage } from '@/api/app/apiError';
import { LoginPayloadSchema } from '@/types/schemas';

import { AuthLayout } from '../layouts/AuthLayout';
import { Button } from '@/shadcn/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/shadcn/components/ui/card';
import { Checkbox } from '@/shadcn/components/ui/checkbox';
import { Label } from '@/shadcn/components/ui/label';
import { Alert, AlertDescription } from '@/shadcn/components/ui/alert';
import { HarmonyInput } from '@/components/ui/harmony-input';
import { STORAGE_KEYS } from '@/lib/storageKeys';
import { ROUTES } from '@/lib/routes';
import { OtpComponent } from '@/components/shared/Otp';
import { useAuth } from '@/shared/AuthContext';

type LoginFormData = z.infer<typeof LoginPayloadSchema>;

function Login() {
  const [isOtpStage, setIsOtpStage] = useState(false);
  const [userEmail, setUserEmail] = useState('');
  const [userRememberMe, setUserRememberMe] = useState(false);
  const [cooldown, setCooldown] = useState(0);

  const navigate = useNavigate();
  const { login } = useAuth();

  const {
    register,
    handleSubmit,
    setValue,
    control,
    formState: { errors },
  } = useForm<LoginFormData>({
    resolver: zodResolver(LoginPayloadSchema),
    mode: 'onChange',
    defaultValues: {
      email: '',
      password: '',
      rememberMe: false,
    },
  });

  useEffect(() => {
    if (cooldown <= 0) return;
    const id = setTimeout(() => setCooldown((s) => s - 1), 1000);
    return () => clearTimeout(id);
  }, [cooldown]);

  const extractWaitSeconds = (msg: string): number => {
    const match = msg.match(/(\d+)\s*second/i);
    return match ? parseInt(match[1], 10) : 0;
  };

  const loginMutation = useMutation({
    mutationFn: (credentials: LoginFormData) => accountService.login(credentials),
    onSuccess: async (response, variables) => {
      setCooldown(0);
      if (response.requiresOtp) {
        if (variables.rememberMe) {
          localStorage.setItem(STORAGE_KEYS.REMEMBERED_EMAIL, variables.email);
        } else {
          localStorage.removeItem(STORAGE_KEYS.REMEMBERED_EMAIL);
        }
        setUserEmail(variables.email);
        setUserRememberMe(variables.rememberMe ?? false);
        setIsOtpStage(true);
      } else {
        if (!response.authResult) return;
        if (variables.rememberMe) {
          localStorage.setItem(STORAGE_KEYS.REMEMBERED_EMAIL, variables.email);
        } else {
          localStorage.removeItem(STORAGE_KEYS.REMEMBERED_EMAIL);
        }
        await login(response.authResult);
        navigate(ROUTES.DASHBOARD);
      }
    },
    onError: (err) => {
      const msg = getApiErrorMessage(err, '');
      const secs = extractWaitSeconds(msg);
      if (secs > 0) setCooldown(secs);
    },
  });

  useEffect(() => {
    const savedEmail = localStorage.getItem(STORAGE_KEYS.REMEMBERED_EMAIL);
    if (savedEmail) {
      setValue('email', savedEmail);
      setValue('rememberMe', true);
    }
  }, [setValue]);

  const onSubmit: SubmitHandler<LoginFormData> = (data) => {
    if (cooldown > 0) return;
    loginMutation.mutate(data);
  };

  return (
    <AuthLayout>
      <Card className="py-8 gap-8">
        {!isOtpStage ? (
          <>
            <CardHeader>
              <CardTitle className="text-2xl font-semibold tracking-tight">Welcome back</CardTitle>
              <CardDescription>Enter your credentials to access Harmony</CardDescription>
            </CardHeader>
            <CardContent className="space-y-5">
              {cooldown > 0 && (
                <Alert variant="destructive">
                  <Clock size={16} />
                  <AlertDescription>
                    Too many attempts. Retry in <strong>{cooldown}s</strong>.
                  </AlertDescription>
                </Alert>
              )}

              <form onSubmit={handleSubmit(onSubmit)} className="space-y-5">
                <HarmonyInput
                  label="Email"
                  type="email"
                  placeholder="name@company.com"
                  leftIcon={<Mail size={16} />}
                  error={errors.email?.message}
                  {...register('email')}
                />

                <HarmonyInput
                  label="Password"
                  type="password"
                  placeholder="••••••••"
                  leftIcon={<Lock size={16} />}
                  error={errors.password?.message}
                  {...register('password')}
                />

                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Controller
                      name="rememberMe"
                      control={control}
                      render={({ field }) => (
                        <Checkbox
                          id="rememberMe"
                          checked={field.value}
                          onCheckedChange={field.onChange}
                        />
                      )}
                    />
                    <Label htmlFor="rememberMe" className="font-normal cursor-pointer">
                      Remember me
                    </Label>
                  </div>
                  <Link
                    to="/forgot-password"
                    className="text-sm text-primary hover:underline"
                  >
                    Forgot password?
                  </Link>
                </div>

                <Button
                  type="submit"
                  className="w-full"
                  disabled={loginMutation.isPending || cooldown > 0}
                >
                  {loginMutation.isPending && <Loader2 className="animate-spin" />}
                  {cooldown > 0 ? `Retry in ${cooldown}s` : 'Sign in'}
                </Button>
              </form>
            </CardContent>
          </>
        ) : (
          <CardContent className="space-y-4 pt-6">
            <OtpComponent email={userEmail} rememberMe={userRememberMe} />
            <Button
              variant="ghost"
              className="w-full"
              onClick={() => setIsOtpStage(false)}
            >
              ← Back to login
            </Button>
          </CardContent>
        )}
      </Card>
    </AuthLayout>
  );
}

export default Login;
